import React, { useEffect } from "react";
import AOS from "aos";
import "aos/dist/aos.css";
import "./HomePage.css";

export default function HomePage() {
  useEffect(() => {
    AOS.init({ duration: 600, once: true });
  }, []);

  return (
    <div className="homepage">

      {/* HERO SECTION */}
      <section className="hero" id="home" data-aos="fade-up">
        <h1>Welcome to CampusConnect</h1>
        <p>Your one-stop platform for all college needs.</p>
        <a href="/dashboard" className="btn">Get Started</a>
      </section>

      {/* SERVICES */}
      <section className="services" id="services">
        <h2 data-aos="fade-up">Our Services</h2>
        <div className="card-container">
          <div className="card" data-aos="fade-right">Notices</div>
          <div className="card" data-aos="fade-up">Internships</div>
          <div className="card" data-aos="fade-left">Placements</div>
        </div>
      </section>

      {/* FEATURES */}
      <section className="features" id="features">
        <h2 data-aos="fade-up">Why Choose Us?</h2>
        <div className="feature-list">
          <div className="feature" data-aos="zoom-in">Easy Access</div>
          <div className="feature" data-aos="zoom-in" data-aos-delay="100">All-in-One</div>
          <div className="feature" data-aos="zoom-in" data-aos-delay="200">Student Friendly</div>
        </div>
      </section>

      {/* GALLERY */}
      <section className="gallery" id="gallery">
        <h2 data-aos="fade-up">Gallery</h2>
        <div className="gallery-images" data-aos="fade-up">
          <div className="img-box">Image 1</div>
          <div className="img-box">Image 2</div>
          <div className="img-box">Image 3</div>
        </div>
      </section>

      {/* TESTIMONIALS */}
      <section className="testimonials" id="testimonials">
        <h2 data-aos="fade-up">Testimonials</h2>
        <div className="testimonial" data-aos="fade-up">"Amazing platform!"</div>
        <div className="testimonial" data-aos="fade-up" data-aos-delay="150">"Very useful for students."</div>
      </section>

      {/* CONTACT */}
      <section className="contact" id="contact">
        <h2 data-aos="fade-up">Contact Us</h2>
        <p data-aos="fade-up">Email: campusconnect@gmail.com</p>
        <p data-aos="fade-up">Phone: +91 9876543210</p>
      </section>

      {/* FOOTER */}
      <footer data-aos="fade-up">
        <p>© 2025 CampusConnect. All rights reserved.</p>
      </footer>

      {/* SCROLL TO TOP */}
      <button onClick={() => window.scrollTo({ top: 0, behavior: "smooth" })} className="scroll-top">
        ⬆
      </button>
    </div>
  );
}
